VALUES
  ('bookkeeper-moex-00562', 'bookkeeper', 'bookkeeper-moex-110-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '臺中公司發行甲、乙兩種公司債，甲公司債採溢價發行，乙公司債採折價發行，並按有效利息法攤銷溢折 價，下列敘述何者正確？', '["甲應付公司債之溢價，列為應付公司債之減項，溢價攤銷作為利息費用調整加項", "乙應付公司債之折價，列為應付公司債之加項，折價攤銷作為利息費用調整減項", "甲應付公司債之溢價，列為應付公司債之加項，溢價攤銷作為利息費用調整減項", "乙應付公司債之折價，列為應付公司債之加項，折價攤銷作為利息費用調整加項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:22+00:00", "source_pdf_sha1": "81589323dc48", "answer_pdf_sha1": "3ac7ea2071dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00563', 'bookkeeper', 'bookkeeper-moex-110-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依商業會計法第5條第2項之規定，關於公司組織主辦會計之任免，除章程有較高規定外，下列敘述何者 正確？', '["在有限公司，應有全體股東過半數之同意", "在股份有限公司，應有董事會以董事過半數之出席，及出席董事過三分之二之同意", "在無限公司，應有全體股東二分之一同意", "在兩合公司，應有全體股東過二分之一同意"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:22+00:00", "source_pdf_sha1": "81589323dc48", "answer_pdf_sha1": "3ac7ea2071dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
